mapper.select:
/* 한전 계약 및 전력관리 정보 조회 */
select 
	site_set_idx, site_id, cust_num, use_elec_addr, meter_num, meter_sf, 
	/*charge_type, */plan_type, plan_type2, plan_type3, plan_name, contract_power, meter_read_day, 
	charge_yearmd, charge_power, charge_rate, goal_power, reduce_amt, smp_rate, rec_rate, rec_weight, profit_ratio, 
	del_yn, reg_uid, reg_date, mod_uid, mod_date, 
	ess_profit_ratio, dr_profit_ratio, pv_profit_ratio, ess_battery, ess_pcs, meter_claim_day, rec_rate_date, smp_rate_date
from tb_site_set
where 1=1
and site_id = #{siteId }

/* 요금제 조회 */
select 
	plan_type, plan_type2, plan_type3, plan_name ,plan_type_name,plan_type_name2,plan_type_name3
from tb_plan_type
where 1=1

and plan_type = #{planType }


and plan_type2 = #{planType2 }


and plan_type3 = #{planType3 }

 
group by plan_type 


group by plan_type, plan_type2 


group by plan_type, plan_type2, plan_type3

/* 요금제 조회 */
select 
	plan_type, plan_type2, plan_type3, plan_name ,summer_val , spring_fall_val, winter_val, basic_val
from tb_plan_type
where 1=1
and plan_type = #{planType }
and plan_type2 = #{planType2 }
and plan_type3 = #{planType3 }

mapper.insert:
/* 한전 계약 및 전력관리 정보 등록 */ insert into tb_site_set (
site_id, /* 사이트ID */ cust_num, /* 고객 번호 */ use_elec_addr, /* 전기사용 장소 */ meter_num, /* 계량기 번호 */ meter_sf, /* 계량기 배수 */ plan_type, /* 요금제구분(general_A1_low_voltage_A 외. bill_api.pdf 참조요망) */ plan_type2, /* 요금제구분(general_A1_low_voltage_A 외. bill_api.pdf 참조요망) */ plan_type3, /* 요금제구분(general_A1_low_voltage_A 외. bill_api.pdf 참조요망) */ plan_name, /* 요금제(일반용 전력 (갑)I 저압전력 외. bill_api.pdf 참조요망) */ contract_power, /* 계약전력(단위:kW) */ meter_read_day, /* 검침일(단위:일) */ charge_yearmd, /* 요금적용기준년월(형식:YYYYMM) */ charge_power, /* 요금적용전력(단위:kW) */ charge_rate, /* 요금적용전력대비(단위:%) */ goal_power, /* 목표전력(단위:kW) */ reduce_amt, /* 감축용량(단위:kW) */ smp_rate, /* SMP단가(System Marginal Price)(단위:원) */ rec_rate, /* REC단가(단위:원) */ rec_weight, /* REC가중치 */ profit_ratio, /* 수익배분 비율 */ del_yn, reg_uid, reg_date, meter_claim_day, /* 청구일 */ rec_rate_date, /* REC단가 일자 */ smp_rate_date /* SMP단가 일자 */ ) values (
#{siteId }, #{custNum }, #{useElecAddr }, #{meterNum }, #{meterSf }, #{planType }, #{planType2 }, #{planType3 }, #{planName }, #{contractPower }, #{meterReadDay }, #{chargeYearmd }, #{chargePower }, #{chargeRate }, #{goalPower }, #{reduceAmt }, #{smpRate }, #{recRate }, #{recWeight }, #{profitRatio }, 'N', #{regUid }, now(), #{meterClaimDay }, #{recRateDate }, #{smpRateDate } )
